// ── Helpers ────────────────────────────────────────────────────
function fmtFecha(ts) {
  if (!ts) return '–'
  try {
    const d = ts.toDate ? ts.toDate() : new Date(ts)
    return d.toLocaleDateString('es-CL', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit' })
  } catch { return '–' }
}

// ── Logo canvas (quita fondo negro) ───────────────────────────
function LogoMPF({ height = 38, style = {} }) {
  const ref = useRef(null)
  useEffect(() => {
    const c = ref.current; if (!c) return
    const ctx = c.getContext('2d', { willReadFrequently: true })
    const img = new Image()
    img.onload = () => {
      const ratio = img.width / img.height
      c.width = Math.round(height * ratio)
      c.height = height
      ctx.drawImage(img, 0, 0, c.width, c.height)
      const d = ctx.getImageData(0, 0, c.width, c.height)
      const px = d.data
      for (let i = 0; i < px.length; i += 4) {
        const lum = 0.299*px[i] + 0.587*px[i+1] + 0.114*px[i+2]
        if (lum < 25) px[i+3] = 0
        else if (lum < 55) px[i+3] = Math.round((lum-25)/30*255)
      }
      ctx.putImageData(d, 0, 0)
    }
    img.src = LOGO_B64
  }, [height])
  return <canvas ref={ref} style={{ height, display:'block', ...style }} />
}

// ── PIN Modal (datos vienen del perfil) ────────────────────────
function PinModal({ session, accion, onSuccess, onClose }) {
  const [pin,     setPin]     = useState('')
  const [error,   setError]   = useState('')
  const [loading, setLoading] = useState(false)

  async function handleFirmar() {
    setError('')
    if (!pin) return setError('Ingresa tu PIN')
    setLoading(true)
    try {
      const tiene = await tienePin(session.usuario)
      if (!tiene) {
        // Si no tiene PIN, crear con este
        if (pin.length < 4) { setError('Mínimo 4 dígitos'); setLoading(false); return }
        await crearPin(session.usuario, pin)
      }
      const ok = await verificarPin(session.usuario, pin)
      if (!ok) { setError('PIN incorrecto'); setLoading(false); return }
      onSuccess()
    } catch(e) { setError(e.message) }
    setLoading(false)
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.6)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:2000 }}>
      <div style={{ background:'#fff', borderRadius:16, padding:'2rem', width:360, boxShadow:'0 24px 64px rgba(0,0,0,0.3)' }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:20 }}>
          <div>
            <div style={{ fontSize:15, fontWeight:700, color:C.navy }}>Firma electrónica</div>
            <div style={{ fontSize:12, color:C.gray, marginTop:2 }}>{accion}</div>
          </div>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:22, cursor:'pointer', color:C.gray }}>×</button>
        </div>

        {/* Datos del firmante — solo lectura */}
        <div style={{ background:C.silver, border:`1px solid ${C.border}`, borderRadius:10, padding:'12px 14px', marginBottom:18 }}>
          <div style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', marginBottom:8 }}>Firmante</div>
          <div style={{ fontSize:13, fontWeight:700, color:C.navy }}>{session.nombre}</div>
          {session.cargo   && <div style={{ fontSize:12, color:C.gray, marginTop:2 }}>{session.cargo}</div>}
          {session.rut     && <div style={{ fontSize:11, color:'#94a3b8', marginTop:1 }}>RUT: {session.rut}</div>}
          {session.empresa && <div style={{ fontSize:11, color:'#94a3b8' }}>{session.empresa}</div>}
        </div>

        <label style={{ fontSize:11, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>
          PIN de firma
        </label>
        <input
          type="password" inputMode="numeric" maxLength={8} autoFocus
          value={pin} onChange={e => { setPin(e.target.value.replace(/\D/g,'')); setError('') }}
          placeholder="••••"
          style={{ width:'100%', padding:'12px', fontSize:24, letterSpacing:10, border:`1.5px solid ${error ? C.red : C.border}`, borderRadius:8, boxSizing:'border-box', outline:'none', textAlign:'center' }}
        />
        {error && <div style={{ marginTop:8, padding:'8px 12px', background:'#fef2f2', borderRadius:8, fontSize:13, color:C.red }}>{error}</div>}
        <button onClick={handleFirmar} disabled={loading} style={{
          width:'100%', marginTop:14, padding:'12px', fontSize:14, fontWeight:700,
          background: loading ? '#94a3b8' : C.navy, color:'#fff', border:'none', borderRadius:10,
          cursor: loading ? 'not-allowed' : 'pointer',
        }}>
          {loading ? 'Procesando...' : 'Firmar'}
        </button>
      </div>
    </div>
  )
}

// ── Badge de estado ────────────────────────────────────────────
function EstadoBadge({ estado }) {
  const e = ESTADOS[estado] || ESTADOS.borrador
  const gradients = {
    borrador:   'linear-gradient(135deg, #94a3b8, #64748b)',
    emitido:    'linear-gradient(135deg, #3B82F6, #1B5E8A)',
    respondido: 'linear-gradient(135deg, #10B981, #059669)',
    cerrado:    'linear-gradient(135deg, #374151, #1f2937)',
  }
  return (
    <span style={{
      padding: '3px 11px', borderRadius: 99, fontSize: 11, fontWeight: 700,
      background: gradients[estado] || gradients.borrador,
      color: '#fff', whiteSpace: 'nowrap',
      boxShadow: '0 1px 5px rgba(0,0,0,0.18)',
    }}>
      {e.label}
    </span>
  )
}

