// ── Modal detalle de folio ─────────────────────────────────────
function FolioModal({ folio, session, onUpdate, onClose }) {
  const [respuesta, setRespuesta] = useState('')
  const [modal,     setModal]     = useState(null)
  const [loading,   setLoading]   = useState(false)

  const libro    = LIBROS[folio.libro]
  const tipoInfo = [...TIPOS_FOLIO.comunicaciones, ...TIPOS_FOLIO.prevencion].find(t => t.key === folio.tipo)
  const esMpf    = ['admin','supervisor','operador'].includes(session.rol)
  const esMandante = session.rol === 'mandante'

  const puedeEmitir    = esMpf && folio.estado === 'borrador' && folio.creadoPor?.usuario === session.usuario
  const puedeResponder = folio.estado === 'emitido' && !folio.respuesta
  const puedeCerrar    = folio.estado === 'respondido' && esMpf

  async function handleEmision() {
    setLoading(true)
    try {
      await firmarEmision(folio.id, {
        usuario: session.usuario,
        nombre:  session.nombre,
        cargo:   session.cargo || '',
      })
      setModal(null); onUpdate()
    } catch(e) { alert(e.message) }
    setLoading(false)
  }

  async function handleResponder() {
    if (!respuesta.trim()) { alert('Escribe una respuesta'); return }
    setLoading(true)
    try {
      await responderFolio(folio.id, {
        contenido: respuesta,
        usuario:   session.usuario,
        nombre:    session.nombre,
        rol:       session.rol,
      })
      await firmarRespuesta(folio.id, {
        usuario: session.usuario,
        nombre:  session.nombre,
        cargo:   session.cargo || '',
      })
      setModal(null); setRespuesta(''); onUpdate()
    } catch(e) { alert(e.message) }
    setLoading(false)
  }

  async function handleCerrar() {
    setLoading(true)
    try {
      await firmarRespuesta(folio.id, {
        usuario: session.usuario,
        nombre:  session.nombre,
        cargo:   session.cargo || '',
      })
      setModal(null); onUpdate()
    } catch(e) { alert(e.message) }
    setLoading(false)
  }

  function imprimirPDF() {
    const html = generarPDFFolio(folio, LOGO_B64)
    const win  = window.open('', '_blank', 'width=960,height=780')
    if (!win) { alert('Activa las ventanas emergentes para generar el PDF'); return }
    win.document.write(html)
    win.document.close()
    setTimeout(() => { win.focus(); win.print(); win.onafterprint = () => win.close() }, 1800)
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.6)', display:'flex', alignItems:'flex-start', justifyContent:'center', zIndex:1500, overflowY:'auto', padding:'2rem 1rem' }}>
      <div style={{ background:'#fff', borderRadius:16, width:'100%', maxWidth:700, boxShadow:'0 24px 64px rgba(0,0,0,0.3)' }}>

        {/* Header del modal */}
        <div style={{ background:C.navy, borderRadius:'16px 16px 0 0', padding:'16px 20px', display:'flex', alignItems:'center', gap:12 }}>
          <div style={{ flex:1 }}>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:4 }}>
              <span style={{ fontFamily:'monospace', fontWeight:700, fontSize:16, color:C.gold }}>{folio.codigo}</span>
              <span style={{ fontSize:12, color:'rgba(255,255,255,0.5)' }}>{libro.label}</span>
            </div>
            <div style={{ fontSize:15, fontWeight:700, color:'#fff' }}>{folio.asunto}</div>
            <div style={{ fontSize:11, color:'rgba(255,255,255,0.5)', marginTop:2 }}>
              {tipoInfo?.label} · {fmtFecha(folio.creadoEn)}
            </div>
          </div>
          <EstadoBadge estado={folio.estado} />
          <button onClick={imprimirPDF} title="Descargar PDF" style={{ background:'rgba(255,255,255,0.1)', border:'1px solid rgba(255,255,255,0.2)', color:'#fff', borderRadius:8, padding:'6px 12px', cursor:'pointer', fontSize:12, fontWeight:600 }}>
            ⬇ PDF
          </button>
          <button onClick={onClose} style={{ background:'none', border:'none', color:'rgba(255,255,255,0.7)', fontSize:22, cursor:'pointer', lineHeight:1 }}>×</button>
        </div>

        <div style={{ padding:'20px' }}>

          {/* Información del creador */}
          <div style={{ display:'flex', gap:8, marginBottom:18 }}>
            <div style={{ background:C.silver, border:`1px solid ${C.border}`, borderRadius:8, padding:'10px 14px', flex:1 }}>
              <div style={{ fontSize:9, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', marginBottom:4 }}>Creado por</div>
              <div style={{ fontSize:13, fontWeight:700, color:C.navy }}>{folio.creadoPor?.nombre}</div>
              <div style={{ fontSize:11, color:C.gray }}>{folio.creadoPor?.rol === 'mandante' ? 'Río Tinto Mining' : 'MPF Ingeniería Civil SpA'}</div>
            </div>
          </div>

          {/* Contenido del folio */}
          <div style={{ marginBottom:18 }}>
            <div style={{ fontSize:11, fontWeight:700, color:C.navy, textTransform:'uppercase', letterSpacing:'.06em', marginBottom:8 }}>Contenido del folio</div>
            <div style={{ background:C.silver, border:`1px solid ${C.border}`, borderRadius:8, padding:'14px', fontSize:13, lineHeight:1.85, color:C.text, whiteSpace:'pre-wrap' }}>
              {folio.contenido}
            </div>
          </div>

          {/* Firma emisor */}
          {folio.firma_emisor && (
            <div style={{ border:`1px solid #bbf7d0`, borderRadius:8, overflow:'hidden', marginBottom:14 }}>
              <div style={{ background:C.navy, padding:'7px 14px', fontSize:9, fontWeight:700, color:C.gold, textTransform:'uppercase', letterSpacing:'2px' }}>
                Firma de emisión
              </div>
              <div style={{ padding:'12px 14px', background:'#f0fdf4', display:'flex', gap:12, alignItems:'center' }}>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:13, fontWeight:700, color:C.navy }}>{folio.firma_emisor.nombre}</div>
                  {folio.firma_emisor.cargo && <div style={{ fontSize:12, color:C.gray }}>{folio.firma_emisor.cargo}</div>}
                </div>
                <div style={{ textAlign:'right', fontSize:12, color:C.gray }}>
                  <div style={{ fontWeight:600 }}>{folio.firma_emisor.fecha}</div>
                  <div>{folio.firma_emisor.hora} hrs CLT</div>
                </div>
              </div>
            </div>
          )}

          {/* Respuesta */}
          {folio.respuesta && (
            <div style={{ border:`1px solid #bfdbfe`, borderRadius:8, overflow:'hidden', marginBottom:14 }}>
              <div style={{ background:C.accent, padding:'7px 14px', fontSize:9, fontWeight:700, color:'#fff', textTransform:'uppercase', letterSpacing:'2px' }}>
                Respuesta · {folio.respuesta.respondidoPor?.nombre}
              </div>
              <div style={{ padding:'12px 14px', background:'#eff6ff' }}>
                <div style={{ fontSize:13, lineHeight:1.8, color:C.text, whiteSpace:'pre-wrap', marginBottom: folio.respuesta.firma ? 10 : 0 }}>
                  {folio.respuesta.contenido}
                </div>
                {folio.respuesta.firma && (
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'8px 12px', background:'#dbeafe', borderRadius:6, fontSize:12 }}>
                    <div>
                      <span style={{ fontWeight:700, color:C.navy }}>{folio.respuesta.firma.nombre}</span>
                      {folio.respuesta.firma.cargo && <span style={{ color:C.gray }}> · {folio.respuesta.firma.cargo}</span>}
                    </div>
                    <div style={{ color:C.gray }}>{folio.respuesta.firma.fecha} {folio.respuesta.firma.hora}</div>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Zona de respuesta (si puede responder) */}
          {puedeResponder && (
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:11, fontWeight:700, color:C.navy, textTransform:'uppercase', letterSpacing:'.06em', marginBottom:8 }}>Escribir respuesta</div>
              <textarea
                value={respuesta} onChange={e => setRespuesta(e.target.value)} rows={4}
                placeholder="Escribe la respuesta oficial al folio..."
                style={{ width:'100%', padding:'10px 12px', fontSize:13, fontFamily:'inherit', lineHeight:1.7, border:`1.5px solid ${C.border}`, borderRadius:8, resize:'vertical', boxSizing:'border-box', outline:'none' }}
              />
            </div>
          )}

          {/* Botones de acción */}
          <div style={{ display:'flex', gap:8, justifyContent:'flex-end', flexWrap:'wrap' }}>
            <button onClick={onClose} style={{ padding:'9px 18px', fontSize:13, background:'transparent', border:`1px solid ${C.border}`, borderRadius:8, cursor:'pointer', color:C.gray }}>
              Cerrar
            </button>
            {puedeEmitir && (
              <button onClick={() => setModal('emitir')} style={{ padding:'9px 18px', fontSize:13, fontWeight:700, background:C.navy, color:'#fff', border:'none', borderRadius:8, cursor:'pointer' }}>
                ✍ Firmar y emitir
              </button>
            )}
            {puedeResponder && (
              <button onClick={() => setModal('responder')} style={{ padding:'9px 18px', fontSize:13, fontWeight:700, background:C.accent, color:'#fff', border:'none', borderRadius:8, cursor:'pointer' }}>
                ✍ Responder y firmar
              </button>
            )}
            {puedeCerrar && (
              <button onClick={() => setModal('cerrar')} style={{ padding:'9px 18px', fontSize:13, fontWeight:700, background:C.green, color:'#fff', border:'none', borderRadius:8, cursor:'pointer' }}>
                ✓ Tomar conocimiento
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Modales PIN */}
      {modal === 'emitir' && (
        <PinModal session={session} accion="Firmar y emitir folio"
          onSuccess={handleEmision} onClose={() => setModal(null)} />
      )}
      {modal === 'responder' && (
        <PinModal session={session} accion="Firmar respuesta al folio"
          onSuccess={handleResponder} onClose={() => setModal(null)} />
      )}
      {modal === 'cerrar' && (
        <PinModal session={session} accion="Tomar conocimiento y cerrar folio"
          onSuccess={handleCerrar} onClose={() => setModal(null)} />
      )}
    </div>
  )
}

// ── Formulario Nuevo Folio ─────────────────────────────────────
function NuevoFolioPanel({ libro, session, onCreado, onClose }) {
  const [tipo,      setTipo]      = useState(TIPOS_FOLIO[libro][0].key)
  const [asunto,    setAsunto]    = useState('')
  const [borrador,  setBorrador]  = useState('')
  const [contenido, setContenido] = useState('')
  const [loading,   setLoading]   = useState(false)
  const [aiLoading, setAiLoading] = useState(false)
  const esMpf = ['admin','supervisor','operador'].includes(session.rol)

  async function generarConIa() {
    if (!asunto.trim()) { alert('Escribe el asunto primero'); return }
    setAiLoading(true)
    const tipoInfo = TIPOS_FOLIO[libro].find(t => t.key === tipo)
    const prompt = `Eres redactor técnico de MPF Ingeniería Civil SPA para el proyecto Río Tinto Mining.
Redacta un folio formal de tipo "${tipoInfo?.label}" para el ${LIBROS[libro].label}.
Asunto: ${asunto}
${borrador ? `Borrador del supervisor:\n${borrador}` : ''}
Redacta en tono formal y técnico. Solo el cuerpo del folio. Máximo 180 palabras.`
    try {
      let text = ''
      await generarConIA(prompt, chunk => { text += chunk; setContenido(text) })
    } catch(e) { alert('Error IA: ' + e.message) }
    setAiLoading(false)
  }

  async function guardar() {
    if (!asunto.trim())    { alert('Ingresa el asunto'); return }
    if (!contenido.trim()) { alert('Ingresa el contenido'); return }
    setLoading(true)
    try {
      const { id, codigo } = await crearFolio({
        libro, tipo, asunto, contenido,
        usuario: session.usuario, nombre: session.nombre, rol: session.rol,
      })
      onCreado(codigo)
    } catch(e) { alert('Error al crear folio: ' + e.message) }
    setLoading(false)
  }

  return (
    <div style={{ background:'#fff', border:`2px solid ${LIBROS[libro].color}`, borderRadius:12, padding:'1.25rem', marginBottom:16 }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:16 }}>
        <div style={{ fontSize:15, fontWeight:700, color:C.navy }}>Nuevo folio</div>
        <button onClick={onClose} style={{ background:'none', border:'none', fontSize:22, cursor:'pointer', color:C.gray }}>×</button>
      </div>

      {/* Tipo */}
      <div style={{ marginBottom:14 }}>
        <label style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>Tipo de folio</label>
        <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
          {TIPOS_FOLIO[libro].map(t => (
            <button key={t.key} onClick={() => setTipo(t.key)} style={{
              padding:'6px 12px', fontSize:12, borderRadius:8, cursor:'pointer',
              border: tipo===t.key ? `2px solid ${LIBROS[libro].color}` : `1px solid ${C.border}`,
              background: tipo===t.key ? `${LIBROS[libro].color}18` : 'transparent',
              color: tipo===t.key ? LIBROS[libro].color : C.gray,
              fontWeight: tipo===t.key ? 700 : 400,
            }}>{t.label}</button>
          ))}
        </div>
      </div>

      {/* Asunto */}
      <div style={{ marginBottom:14 }}>
        <label style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>Asunto</label>
        <input value={asunto} onChange={e=>setAsunto(e.target.value)} placeholder="Describe el asunto del folio"
          style={{ width:'100%', padding:'9px 12px', fontSize:14, border:`1px solid ${C.border}`, borderRadius:8, boxSizing:'border-box', outline:'none' }} />
      </div>

      {/* IA (solo MPF) */}
      {esMpf && (
        <div style={{ marginBottom:14 }}>
          <label style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>Borrador (opcional — la IA redacta formal)</label>
          <textarea value={borrador} onChange={e=>setBorrador(e.target.value)} rows={2}
            placeholder="Escribe tus ideas, la IA las transforma en lenguaje técnico formal..."
            style={{ width:'100%', padding:'9px 12px', fontSize:13, fontFamily:'inherit', border:`1px solid ${C.border}`, borderRadius:8, resize:'vertical', boxSizing:'border-box', outline:'none', marginBottom:8 }} />
          <button onClick={generarConIa} disabled={aiLoading} style={{
            padding:'7px 14px', fontSize:12, fontWeight:700,
            background: aiLoading ? '#94a3b8' : C.accent, color:'#fff', border:'none', borderRadius:8, cursor: aiLoading ? 'not-allowed' : 'pointer',
          }}>
            {aiLoading ? 'Redactando...' : '✦ Redactar con IA'}
          </button>
        </div>
      )}

      {/* Contenido */}
      <div style={{ marginBottom:14 }}>
        <label style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>Contenido del folio</label>
        <textarea value={contenido} onChange={e=>setContenido(e.target.value)} rows={6}
          placeholder="Contenido formal del folio..."
          style={{ width:'100%', padding:'9px 12px', fontSize:13, fontFamily:'inherit', lineHeight:1.7, border:`1px solid ${C.border}`, borderRadius:8, resize:'vertical', boxSizing:'border-box', outline:'none' }} />
      </div>

      <div style={{ display:'flex', gap:8, justifyContent:'flex-end' }}>
        <button onClick={onClose} style={{ padding:'9px 18px', fontSize:13, background:'transparent', border:`1px solid ${C.border}`, borderRadius:8, cursor:'pointer', color:C.gray }}>
          Cancelar
        </button>
        <button onClick={guardar} disabled={loading} style={{
          padding:'9px 20px', fontSize:13, fontWeight:700,
          background: loading ? '#94a3b8' : C.navy, color:'#fff', border:'none', borderRadius:8,
          cursor: loading ? 'not-allowed' : 'pointer',
        }}>
          {loading ? 'Guardando...' : 'Guardar borrador'}
        </button>
      </div>
    </div>
  )
}

// ── Row de folio en lista ──────────────────────────────────────
function FolioRow({ folio, onClick }) {
  const libro    = LIBROS[folio.libro]
  const tipoInfo = [...TIPOS_FOLIO.comunicaciones, ...TIPOS_FOLIO.prevencion].find(t => t.key === folio.tipo)
  const pendiente = folio.estado === 'emitido' && !folio.respuesta

  return (
    <div onClick={onClick}
      className="folio-row"
      style={{
        background: '#fff',
        border: `1px solid ${pendiente ? '#fde68a' : '#e8eef5'}`,
        borderLeft: pendiente ? '4px solid #f59e0b' : `4px solid ${libro.color}`,
        borderRadius: 12, padding: '13px 16px', cursor: 'pointer',
        transition: 'all .18s ease',
        marginBottom: 8,
        boxShadow: pendiente ? '0 2px 14px rgba(245,158,11,0.1)' : '0 1px 4px rgba(0,0,0,0.04)',
      }}>
      <div style={{ display:'flex', alignItems:'center', gap:12 }}>
        {/* Código — badge con gradiente */}
        <div style={{
          fontFamily: 'monospace', fontWeight: 800, fontSize: 12,
          color: '#fff',
          background: `linear-gradient(135deg, ${libro.color} 0%, ${libro.color}cc 100%)`,
          padding: '4px 10px', borderRadius: 8,
          minWidth: 65, flexShrink: 0, textAlign: 'center',
          boxShadow: `0 2px 8px ${libro.color}35`,
          letterSpacing: '0.03em',
        }}>
          {folio.codigo}
        </div>

        {/* Info principal */}
        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ fontSize:13, fontWeight:700, color:'#0F2035', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', marginBottom:3 }}>
            {folio.asunto}
          </div>
          <div style={{ fontSize:11, color:'#94a3b8', display:'flex', alignItems:'center', gap:5, flexWrap:'wrap' }}>
            <span>{tipoInfo?.label}</span>
            <span>·</span>
            <span>{folio.creadoPor?.nombre}</span>
            <span>·</span>
            <span>{fmtFecha(folio.creadoEn)}</span>
            {pendiente && (
              <span style={{
                background: 'rgba(245,158,11,0.1)', color:'#d97706', fontWeight:700,
                padding: '1px 8px', borderRadius: 99, fontSize: 10,
                border: '1px solid rgba(245,158,11,0.22)',
              }}>
                Requiere respuesta
              </span>
            )}
          </div>
        </div>

        {/* Estado + flecha */}
        <div style={{ flexShrink:0, display:'flex', alignItems:'center', gap:8 }}>
          <EstadoBadge estado={folio.estado} />
          <span style={{ color:'#cbd5e1', fontSize:16, flexShrink:0 }}>›</span>
        </div>
      </div>
    </div>
  )
}

// ── Página principal ───────────────────────────────────────────
export default function LibroObras() {
  const session = getSession()
  const [libroActivo,  setLibroActivo]  = useState('comunicaciones')
  const [folios,       setFolios]       = useState([])
  const [loading,      setLoading]      = useState(true)
  const [mostrarForm,  setMostrarForm]  = useState(false)
  const [folioDetalle, setFolioDetalle] = useState(null)
  const [filtroEstado, setFiltroEstado] = useState('todos')
  const [busqueda,     setBusqueda]     = useState('')

  useEffect(() => { cargar() }, [libroActivo])

  async function cargar() {
    setLoading(true)
    try {
      const data = await obtenerFolios(libroActivo)
      setFolios(data)
    } catch(e) { console.error(e) }
    setLoading(false)
  }

  async function recargarYVerFolio(folioId) {
    await cargar()
    // Recargar el folio actualizado para el modal
    try {
      const f = await getFolio(folioId)
      if (f) setFolioDetalle(f)
    } catch {}
  }

  const libro = LIBROS[libroActivo]

  const foliosFiltrados = folios
    .filter(f => filtroEstado === 'todos' || f.estado === filtroEstado)
    .filter(f => !busqueda || f.asunto?.toLowerCase().includes(busqueda.toLowerCase()) || f.codigo?.toLowerCase().includes(busqueda.toLowerCase()))

  const stats = {
    total:      folios.length,
    emitidos:   folios.filter(f => f.estado === 'emitido').length,
    respondidos:folios.filter(f => f.estado === 'respondido').length,
    cerrados:   folios.filter(f => f.estado === 'cerrado').length,
    pendientes: folios.filter(f => f.estado === 'emitido' && !f.respuesta).length,
  }

  const esMpf = ['admin','supervisor','operador'].includes(session?.rol)

  return (
    <div>
      <style>{`
        @keyframes tabShimmer {
          0%   { transform: translateX(-200%); }
          100% { transform: translateX(200%);  }
        }
        @keyframes badgePulse {
          0%,100% { opacity:1; }
          50%     { opacity:.6; }
        }
        @keyframes dotBounce {
          0%,80%,100% { transform:scale(.6); opacity:.4; }
          40%         { transform:scale(1);  opacity:1;  }
        }
        @keyframes slideUpFadeIn {
          from { opacity:0; transform:translateY(12px); }
          to   { opacity:1; transform:translateY(0); }
        }
        .folio-row:hover {
          box-shadow: 0 6px 22px rgba(0,0,0,0.09) !important;
          transform: translateY(-1px);
          border-color: #d1dce8 !important;
        }
        .libro-tab-btn:hover:not(.libro-tab-active) {
          box-shadow: 0 4px 16px rgba(0,0,0,0.08) !important;
          transform: translateY(-1px);
        }
        .stat-card { transition: transform .15s, box-shadow .15s; }
        .stat-card:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(0,0,0,0.1) !important; }
        .filter-pill { transition: all .18s ease; font-family: inherit; }
        .filter-pill:hover { transform: translateY(-1px); }
        .nuevo-btn { transition: all .18s ease; font-family: inherit; }
        .nuevo-btn:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(0,0,0,0.2) !important; }
      `}</style>

      {/* ── Header ── */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:28, animation:'slideUpFadeIn .35s ease' }}>
        <div>
          <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:8 }}>
            <div style={{
              width:42, height:42, borderRadius:12, flexShrink:0,
              background:`linear-gradient(135deg, ${libro.color} 0%, ${libro.color}bb 100%)`,
              display:'flex', alignItems:'center', justifyContent:'center',
              boxShadow:`0 4px 14px ${libro.color}40`,
              transition:'background .3s, box-shadow .3s',
            }}>
              {libroActivo === 'comunicaciones' ? (
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                  <path d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" stroke="#fff" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              ) : (
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                  <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" stroke="#fff" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              )}
            </div>
            <div>
              <h1 style={{ fontSize:24, fontWeight:800, color:'#0F2035', marginBottom:2, letterSpacing:'-0.03em', fontFamily:'Outfit, sans-serif', lineHeight:1.1 }}>
                Libro de Obras Digital
              </h1>
              <p style={{ fontSize:13, color:'#64748b', margin:0 }}>Comunicación oficial MPF Ingeniería Civil ↔ Río Tinto Mining</p>
            </div>
          </div>
          <div style={{ height:3, width:52, borderRadius:2, background:`linear-gradient(90deg, ${libro.color}, ${libro.color}77)`, transition:'background .3s' }} />
        </div>
        <LogoMPF height={34} />
      </div>

      {/* ── Selector de libro — CARD TABS ── */}
      <div style={{ display:'flex', gap:14, marginBottom:24 }}>
        {Object.entries(LIBROS).map(([key, lib]) => {
          const isActive = libroActivo === key
          const icon = key === 'comunicaciones' ? (
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
              <path d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"
                stroke={isActive ? '#fff' : lib.color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          ) : (
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
              <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z"
                stroke={isActive ? '#fff' : lib.color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          )
          return (
            <button
              key={key}
              onClick={() => { setLibroActivo(key); setMostrarForm(false); setFiltroEstado('todos') }}
              className={`libro-tab-btn${isActive ? ' libro-tab-active' : ''}`}
              style={{
                flex: 1,
                padding: '18px 20px',
                borderRadius: 16,
                border: isActive ? 'none' : `1.5px solid ${lib.color}28`,
                background: isActive
                  ? `linear-gradient(135deg, ${lib.color} 0%, ${lib.color}cc 100%)`
                  : '#fff',
                color: isActive ? '#fff' : '#64748b',
                cursor: 'pointer',
                textAlign: 'left',
                fontFamily: 'inherit',
                transition: 'all .22s ease',
                boxShadow: isActive
                  ? `0 8px 28px ${lib.color}40, 0 2px 8px rgba(0,0,0,0.08)`
                  : '0 1px 6px rgba(0,0,0,0.05)',
                transform: isActive ? 'translateY(-3px)' : 'none',
                position: 'relative',
                overflow: 'hidden',
              }}>
              {/* Shimmer animado en estado activo */}
              {isActive && (
                <div style={{
                  position:'absolute', top:0, left:0, width:'40%', height:'100%',
                  background:'linear-gradient(90deg, transparent, rgba(255,255,255,0.12), transparent)',
                  animation:'tabShimmer 3s ease infinite',
                  pointerEvents:'none',
                }} />
              )}
              <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:10, position:'relative' }}>
                <div style={{
                  width:38, height:38, borderRadius:11, flexShrink:0,
                  background: isActive ? 'rgba(255,255,255,0.2)' : `${lib.color}14`,
                  display:'flex', alignItems:'center', justifyContent:'center',
                  boxShadow: isActive ? 'inset 0 1px 2px rgba(255,255,255,0.2)' : 'none',
                }}>
                  {icon}
                </div>
                {isActive && stats.pendientes > 0 && (
                  <span style={{
                    marginLeft:'auto',
                    background:'rgba(255,255,255,0.22)',
                    color:'#fff', fontSize:11, fontWeight:700,
                    padding:'3px 9px', borderRadius:99,
                    border:'1px solid rgba(255,255,255,0.3)',
                    animation:'badgePulse 2.5s ease infinite',
                  }}>
                    {stats.pendientes} pend.
                  </span>
                )}
                {!isActive && stats.pendientes > 0 && key !== libroActivo && (
                  <span style={{
                    marginLeft:'auto',
                    background:`${lib.color}15`, color:lib.color,
                    fontSize:11, fontWeight:700,
                    padding:'3px 9px', borderRadius:99,
                    border:`1px solid ${lib.color}30`,
                  }}>...</span>
                )}
              </div>
              <div style={{ fontSize:15, fontWeight:800, lineHeight:1.2, marginBottom:4, fontFamily:'Outfit, sans-serif', position:'relative' }}>
                {lib.label}
              </div>
              <div style={{ fontSize:11, lineHeight:1.45, opacity: isActive ? 0.78 : 0.55, position:'relative' }}>
                {key === 'comunicaciones' ? 'Comunicados formales MPF ↔ mandante' : 'Gestión de riesgos y seguridad laboral'}
              </div>
            </button>
          )
        })}
      </div>

      {/* ── Stats + botón nuevo ── */}
      <div style={{ display:'flex', gap:8, marginBottom:16, flexWrap:'wrap', alignItems:'center' }}>
        {[
          { label:'TOTAL',       value:stats.total,       gradient:'linear-gradient(135deg, #94a3b8, #64748b)' },
          { label:'EMITIDOS',    value:stats.emitidos,    gradient:`linear-gradient(135deg, ${libro.color}, ${libro.color}99)` },
          { label:'RESPONDIDOS', value:stats.respondidos, gradient:'linear-gradient(135deg, #10B981, #059669)' },
          { label:'CERRADOS',    value:stats.cerrados,    gradient:'linear-gradient(135deg, #374151, #1f2937)' },
          ...(stats.pendientes > 0 ? [{ label:'PENDIENTES', value:stats.pendientes, gradient:'linear-gradient(135deg, #F59E0B, #d97706)' }] : []),
        ].map(s => (
          <div key={s.label} className="stat-card" style={{
            background:'#fff', border:'1px solid #e8eef5', borderRadius:11,
            padding:'10px 16px 10px', textAlign:'center', minWidth:76,
            boxShadow:'0 1px 6px rgba(0,0,0,0.05)', position:'relative', overflow:'hidden',
          }}>
            <div style={{ position:'absolute', top:0, left:0, right:0, height:3, background:s.gradient, borderRadius:'11px 11px 0 0' }} />
            <div style={{ fontSize:22, fontWeight:800, color:'#0F2035', lineHeight:1, fontFamily:'Outfit,sans-serif', marginTop:4 }}>{s.value}</div>
            <div style={{ fontSize:9, color:'#94a3b8', marginTop:3, fontWeight:700, letterSpacing:'.06em' }}>{s.label}</div>
          </div>
        ))}
        <div style={{ flex:1 }} />
        {(esMpf || session?.rol === 'mandante') && (
          <button onClick={() => setMostrarForm(!mostrarForm)} className="nuevo-btn" style={{
            padding:'10px 22px', fontSize:13, fontWeight:700,
            background: mostrarForm
              ? '#f1f5f9'
              : `linear-gradient(135deg, ${libro.color} 0%, ${libro.color}cc 100%)`,
            color: mostrarForm ? C.gray : '#fff',
            border: mostrarForm ? `1px solid ${C.border}` : 'none',
            borderRadius:11, cursor:'pointer',
            boxShadow: mostrarForm ? 'none' : `0 4px 16px ${libro.color}40`,
          }}>
            {mostrarForm ? '× Cancelar' : '+ Nuevo folio'}
          </button>
        )}
      </div>

      {/* Formulario nuevo folio */}
      {mostrarForm && (
        <NuevoFolioPanel
          libro={libroActivo} session={session}
          onCreado={codigo => { setMostrarForm(false); cargar() }}
          onClose={() => setMostrarForm(false)}
        />
      )}

      {/* ── Barra de búsqueda y filtros ── */}
      <div style={{ display:'flex', gap:8, marginBottom:14, flexWrap:'wrap', alignItems:'center' }}>
        <div style={{ flex:'1 1 200px', position:'relative' }}>
          <svg style={{ position:'absolute', left:10, top:'50%', transform:'translateY(-50%)', pointerEvents:'none' }}
            width="14" height="14" viewBox="0 0 24 24" fill="none">
            <path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" stroke="#94a3b8" strokeWidth="2" strokeLinecap="round"/>
          </svg>
          <input
            value={busqueda} onChange={e => setBusqueda(e.target.value)}
            placeholder="Buscar por asunto o código..."
            style={{ width:'100%', padding:'9px 12px 9px 32px', fontSize:13, border:'1.5px solid #e2e8f0', borderRadius:9, outline:'none', boxSizing:'border-box', transition:'border-color .15s', background:'#fff' }}
          />
        </div>
        <div style={{ display:'flex', gap:5, flexWrap:'wrap' }}>
          {['todos','borrador','emitido','respondido','cerrado'].map(e => (
            <button key={e} onClick={() => setFiltroEstado(e)} className="filter-pill" style={{
              padding:'6px 14px', fontSize:11, fontWeight:700, borderRadius:99, cursor:'pointer',
              border: filtroEstado===e ? 'none' : '1.5px solid #e2e8f0',
              background: filtroEstado===e
                ? `linear-gradient(135deg, ${libro.color} 0%, ${libro.color}cc 100%)`
                : '#fff',
              color: filtroEstado===e ? '#fff' : '#64748b',
              boxShadow: filtroEstado===e ? `0 3px 10px ${libro.color}35` : '0 1px 3px rgba(0,0,0,0.04)',
              transform: filtroEstado===e ? 'translateY(-1px)' : 'none',
            }}>{e === 'todos' ? 'Todos' : ESTADOS[e]?.label}</button>
          ))}
        </div>
      </div>

      {/* ── Lista ── */}
      {loading ? (
        <div style={{ textAlign:'center', padding:'3rem', color:'#94a3b8' }}>
          <div style={{ display:'flex', justifyContent:'center', gap:6, marginBottom:12 }}>
            {[0,1,2].map(i => (
              <div key={i} style={{ width:9, height:9, borderRadius:'50%', background:libro.color, animation:'dotBounce 1.2s ease infinite', animationDelay:`${i*0.2}s` }}/>
            ))}
          </div>
          <div style={{ fontSize:13, fontWeight:500 }}>Cargando folios...</div>
        </div>
      ) : foliosFiltrados.length === 0 ? (
        <div style={{
          textAlign:'center', padding:'3.5rem 2rem',
          background:'linear-gradient(135deg, #f8fafc, #f0f4ff)',
          border:`1.5px dashed ${libro.color}35`, borderRadius:16,
          animation:'slideUpFadeIn .4s ease',
        }}>
          <div style={{
            width:56, height:56, borderRadius:16, margin:'0 auto 16px',
            background:`linear-gradient(135deg, ${libro.color}18, ${libro.color}0c)`,
            border:`2px solid ${libro.color}25`,
            display:'flex', alignItems:'center', justifyContent:'center',
          }}>
            {libroActivo === 'comunicaciones' ? (
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                <path d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" stroke={libro.color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            ) : (
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" stroke={libro.color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            )}
          </div>
          <div style={{ fontSize:16, fontWeight:700, color:'#0F2035', marginBottom:6, fontFamily:'Outfit,sans-serif' }}>
            {busqueda ? 'Sin resultados' : filtroEstado !== 'todos' ? `Sin folios "${ESTADOS[filtroEstado]?.label}"` : 'Sin folios todavía'}
          </div>
          <div style={{ fontSize:13, color:'#94a3b8', lineHeight:1.6 }}>
            {busqueda
              ? `No hay folios que coincidan con "${busqueda}"`
              : filtroEstado !== 'todos'
              ? `Prueba con otro filtro o crea un nuevo folio`
              : 'Crea el primer folio usando el botón "+ Nuevo folio"'}
          </div>
        </div>
      ) : (
        <div>
          {foliosFiltrados.map(folio => (
            <FolioRow key={folio.id} folio={folio} onClick={() => setFolioDetalle(folio)} />
          ))}
        </div>
      )}

      {/* Modal de detalle */}
      {folioDetalle && (
        <FolioModal
          folio={folioDetalle}
          session={session}
          onUpdate={() => recargarYVerFolio(folioDetalle.id)}
          onClose={() => { setFolioDetalle(null); cargar() }}
        />
      )}
    </div>
  )
}
